import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is average return on investment?", a: "Average return measures how much an investment gains or loses over time, usually expressed as an annual percentage." },
  { q: "What is CAGR?", a: "CAGR, or compound annual growth rate, is the constant annual return that would turn a beginning value into an ending value over a period." },
  { q: "What is the difference between arithmetic and geometric mean return?", a: "Arithmetic mean averages annual returns directly, while geometric mean accounts for compounding and is usually better for long-term investment performance." },
  { q: "What is a good average return on investments?", a: "A good return depends on risk, time horizon, fees, inflation, and asset type. Broad stock indexes have historically averaged higher returns than cash or bonds." },
  { q: "How do you annualize a return?", a: "To annualize a return, divide total growth into equal yearly compound growth using the CAGR formula." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const percent = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function parseReturns(input: string) {
  return input.split(",").map((x) => Number(x.trim())).filter((x) => Number.isFinite(x));
}

function cagrFromReturns(returns: number[]) {
  if (!returns.length) return 0;
  const product = returns.reduce((acc, value) => acc * (1 + value / 100), 1);
  return (Math.pow(product, 1 / returns.length) - 1) * 100;
}

const exampleReturns = [12, -5, 18, 7, -10, 15, 9, 4, 11, 6];

export default function AverageReturnCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState("series");
  const [returnsInput, setReturnsInput] = useState("12, -5, 18, 7, -10, 15, 9, 4, 11, 6");
  const [beginning, setBeginning] = useState(10000);
  const [ending, setEnding] = useState(18500);
  const [years, setYears] = useState(5);

  const result = useMemo(() => {
    if (mode === "values") {
      const totalReturn = beginning > 0 ? ((ending - beginning) / beginning) * 100 : 0;
      const arithmetic = years > 0 ? totalReturn / years : 0;
      const geometric = beginning > 0 && years > 0 ? (Math.pow(ending / beginning, 1 / years) - 1) * 100 : 0;
      return { arithmetic, geometric, difference: arithmetic - geometric, totalReturn, count: years };
    }
    const returns = parseReturns(returnsInput);
    const arithmetic = returns.length ? returns.reduce((sum, value) => sum + value, 0) / returns.length : 0;
    const geometric = cagrFromReturns(returns);
    return { arithmetic, geometric, difference: arithmetic - geometric, totalReturn: returns.reduce((acc, value) => acc * (1 + value / 100), 1) * 100 - 100, count: returns.length };
  }, [mode, returnsInput, beginning, ending, years]);

  let portfolio = 10000;
  const exampleRows = exampleReturns.map((returnValue, index) => {
    portfolio *= 1 + returnValue / 100;
    const partial = exampleReturns.slice(0, index + 1);
    const arithmetic = partial.reduce((sum, value) => sum + value, 0) / partial.length;
    const geometric = cagrFromReturns(partial);
    return { year: index + 1, returnValue, portfolio, arithmetic, geometric };
  });

  return (
    <>
      <SEOHead title="Free Average Return Calculator Online - Calculate Arithmetic and Geometric Mean Return Instantly | CalcHive" description="Free online average return calculator. Calculate arithmetic and geometric average investment returns and CAGR for any series of annual returns instantly. 100% free, no signup required." canonical="/average-return-calculator" keywords="free average return calculator, CAGR calculator free online, geometric mean return calculator free, arithmetic vs geometric return calculator free, investment return calculator free" category="Financial Calculators" breadcrumbName="Free Average Return Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Average Return Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate arithmetic average return, geometric average return, and CAGR from return series or beginning and ending values.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Input method</label><select value={mode} onChange={(e) => setMode(e.target.value)} className={inputClass}><option value="series">Annual returns</option><option value="values">Beginning and ending values</option></select></div>
            {mode === "series" ? <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Annual returns separated by commas (%)</label><input value={returnsInput} onChange={(e) => setReturnsInput(e.target.value)} className={inputClass} /></div> : <>
              <div><label className="text-sm font-semibold text-foreground block mb-2">Beginning value</label><input type="number" value={beginning} onChange={(e) => setBeginning(Number(e.target.value))} className={inputClass} /></div>
              <div><label className="text-sm font-semibold text-foreground block mb-2">Ending value</label><input type="number" value={ending} onChange={(e) => setEnding(Number(e.target.value))} className={inputClass} /></div>
              <div><label className="text-sm font-semibold text-foreground block mb-2">Years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
            </>}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Geometric Average Return</p><p className="text-5xl sm:text-6xl font-black text-white">{percent(result.geometric)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Arithmetic average</p><p className="text-lg font-extrabold text-foreground">{percent(result.arithmetic)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total return</p><p className="text-lg font-extrabold text-foreground">{percent(result.totalReturn)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Difference</p><p className="text-lg font-extrabold text-foreground">{percent(result.difference)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Average Investment Return for Free</h2><p className="text-muted-foreground leading-relaxed">Enter annual returns to calculate both a simple arithmetic average and a compounded geometric average return.</p>
          <h2 className="text-2xl font-bold text-foreground">Arithmetic vs Geometric Mean Return - What Is the Difference</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Arithmetic vs Geometric Return - Example Portfolio</caption><thead className="bg-muted/60"><tr>{["Year", "Annual Return", "Portfolio Value", "Arithmetic Avg", "Geometric Avg (CAGR)"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{exampleRows.map((row) => <tr key={row.year}><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3">{percent(row.returnValue)}</td><td className="py-2.5 px-3">{money(row.portfolio)}</td><td className="py-2.5 px-3">{percent(row.arithmetic)}</td><td className="py-2.5 px-3">{percent(row.geometric)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free CAGR and Investment Return Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Geometric return is usually the better long-term investment measure because it reflects the effect of compounding through gains and losses.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/average-return-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


